/* ---------------------------------------------------------------
 * Patch UI design tokens.
 *
 * Source of truth: packages/react/DESIGN.md.
 *
 * The system is a crisp-minimal, near-flat design language:
 *   - A near-black flat canvas in both themes (#08090A dark, #FBFBFC light).
 *   - A four-step surface ladder that carries hierarchy without shadow.
 *   - 1px hairline borders as the load-bearing separator.
 *   - A monochrome primary (consumers override --primary to inject brand).
 *   - Semantic status roles at fixed hex, theme-invariant.
 *   - Three type families: Inter Display (600), Inter (400/500), JetBrains
 *     Mono (400). Compound utility classes bundle size + line-height +
 *     tracking + weight into a single .text-<family>-<size> recipe.
 *   - Motion is fast: 75ms state, 150ms overlay, one easing curve.
 *
 * Layers:
 *   1. Raw runtime custom properties on :root / .dark.
 *   2. @theme inline bridge into Tailwind v4 utilities.
 *   3. @layer utilities compound text classes.
 *   4. @layer base thin-scrollbar defaults.
 * --------------------------------------------------------------- */

/* ---------------------------------------------------------------
 * Layer 1: Runtime theme values (light mode reference).
 * --------------------------------------------------------------- */
:root {
  /* Canvas + 4-step surface ladder. Every surface picks a rung.
     Canvas is page bg; surface-1 is the default lifted card; surface-2
     is elevated/hovered; surface-3 is popups (menu, dropdown, select);
     surface-4 is nested tiles inside a lifted panel. */
  --canvas:    #FBFBFB;
  --surface-1: #F5F5F7;
  --surface-2: #EDEDEE;
  --surface-3: #E5E5E7;
  --surface-4: #DEDEE0;

  /* Elevated surface: popups (menu, combobox, command, tooltip) sit on
     this. In light mode it lifts TOWARD pure white so a floating panel
     reads brighter than the off-white canvas below. In dark mode it
     lifts TOWARD lighter gray. Standard crisp-minimal popup treatment. */
  --surface-elevated:       #FFFFFF;
  /* Subtle hover tint for elevated surfaces (secondary Button, Card,
     etc.). Sits between elevated and surface-1 so the hover reads as
     "same surface, slightly tinted" rather than dropping a full rung. */
  --surface-elevated-hover: #F7F7F8;

  /* Hairlines. 1px borders carry every separation the surface ladder
     can't. hairline-strong is for focused/hovered inputs and elevated
     card edges; hairline-tertiary is for nested content that already
     sits on a lifted surface. */
  --hairline:           rgba(0, 0, 0, 0.04);
  --hairline-strong:    rgba(0, 0, 0, 0.08);
  --hairline-tertiary:  rgba(0, 0, 0, 0.14);

  /* Ink (text) tiers. Neutral gray, no cool bias. Icon color inherits
     from surrounding text color. */
  --ink:           #1D1D1F;
  --ink-muted:     #545458;
  --ink-subtle:    #6E6E71;
  --ink-tertiary:  #8E8E93;

  /* Primary (monochrome). No chromatic brand hue ships. Consumers
     redefine these four tokens in a downstream layer to inject brand;
     every Button and focus-adjacent primitive inherits for free. */
  --primary:         var(--ink);
  --on-primary:      var(--canvas);
  /* Hover / active are proportional shifts off --primary via color-mix
     so a consumer's brand override on --primary automatically produces
     matching hover/active steps. Mixing with --canvas gives a "subtle
     move toward the background" that works in both themes: in light
     mode it lightens the dark primary, in dark mode it darkens the
     near-white primary. Avoids ink-muted/subtle which are much lighter
     tiers and would drop the button visibly on hover. */
  --primary-hover:   color-mix(in srgb, var(--primary), var(--canvas) 15%);
  --primary-active:  color-mix(in srgb, var(--primary), var(--canvas) 25%);

  /* Semantic status. Fixed hex, theme-invariant. -fg tokens carry the
     label color so fill and text invert together per theme without a
     callsite dark: variant. Hover/active shift lightness only. */
  --error:         #DC2626;
  --error-hover:   #B91C1C;
  --error-active:  #991B1B;
  --error-fg:      #FFFFFF;
  --warning:        #FDB203;
  --warning-hover:  #D69800;
  --warning-active: #A97007;
  --warning-fg:     #171717;
  --success:        #397C3B;
  --success-hover:  #2D602D;
  --success-active: #234A23;
  --success-fg:     #FFFFFF;

  /* Focus. 2px ring offset 2px outside the element border. The color
     reads --primary so the ring is monochrome ink by default and picks
     up a consumer's brand color for free when they override --primary
     -- every focused primitive gets a brand-colored ring without any
     callsite edits. The 2px + 2px pair sits clearly outside the
     component border rather than merging into it. */
  --focus-ring-color:  var(--primary);
  --focus-ring-width:  2px;
  --focus-ring-offset: 2px;

  /* Overlay scrim (dialog / drawer backdrop). */
  --scrim: rgba(0, 0, 0, 0.45);

  /* Radius. Five values, everything maps to one.
     radius-4 is reserved for very small controls (checkbox, radio thumb)
     where 6px would look proportionally too round. */
  --radius-4:    4px;
  --radius-6:    6px;
  --radius-12:   12px;
  --radius-16:   16px;
  --radius-full: 9999px;

  /* Shadows. Cards and panels are flat; shadows only appear at true
     overlay altitude (menu popup, dialog, tooltip, toast). Stacked
     triple fakes depth: 1px top edge for crispness, mid diffusion for
     the body of the lift, long soft drop for the cast. */
  --shadow-card:
    0 2px 2px rgba(0, 0, 0, 0.04);
  --shadow-menu:
    0 1px 1px rgba(0, 0, 0, 0.02),
    0 4px 8px -4px rgba(0, 0, 0, 0.04),
    0 16px 24px -8px rgba(0, 0, 0, 0.06);
  --shadow-modal:
    0 1px 1px rgba(0, 0, 0, 0.02),
    0 8px 16px -4px rgba(0, 0, 0, 0.04),
    0 24px 32px -8px rgba(0, 0, 0, 0.06);
  --shadow-tooltip: var(--shadow-menu);

  /* Motion. Two durations, one easing curve. */
  --duration-state:   75ms;
  --duration-overlay: 150ms;
  --ease-standard:    cubic-bezier(0.175, 0.885, 0.32, 1.1);

  /* Font families. Consumers ship these through their font pipeline;
     the docs site loads Inter and JetBrains Mono via next/font, which
     exposes CSS vars (--font-body-loaded, --font-mono-loaded) picked
     up first below. When those vars aren't defined the raw family
     names take over, and finally the system fallback stack. Large-size
     optical adjustments in Inter Display are lost if unavailable. */
  --font-display: var(--font-body-loaded), "Inter Display", "Inter", -apple-system, system-ui, "Segoe UI", Roboto, sans-serif;
  --font-body:    var(--font-body-loaded), "Inter", -apple-system, system-ui, "Segoe UI", Roboto, sans-serif;
  --font-mono:    var(--font-mono-loaded), "JetBrains Mono", ui-monospace, "SF Mono", Menlo, monospace;

  /* Display family (Inter Display 600). Aggressive negative tracking
     tapers linearly from -0.045em at 72px to -0.02em at 20px. */
  --display-72-size: 72px; --display-72-leading: 1.05; --display-72-tracking: -0.045em; --display-72-weight: 600;
  --display-64-size: 64px; --display-64-leading: 1.05; --display-64-tracking: -0.04em;  --display-64-weight: 600;
  --display-56-size: 56px; --display-56-leading: 1.08; --display-56-tracking: -0.04em;  --display-56-weight: 600;
  --display-48-size: 48px; --display-48-leading: 1.10; --display-48-tracking: -0.035em; --display-48-weight: 600;
  --display-40-size: 40px; --display-40-leading: 1.15; --display-40-tracking: -0.035em; --display-40-weight: 600;
  --display-32-size: 32px; --display-32-leading: 1.20; --display-32-tracking: -0.03em;  --display-32-weight: 600;
  --display-24-size: 24px; --display-24-leading: 1.25; --display-24-tracking: -0.025em; --display-24-weight: 600;
  --display-20-size: 20px; --display-20-leading: 1.30; --display-20-tracking: -0.02em;  --display-20-weight: 600;

  /* Body family (Inter 400). Default running text. */
  --body-20-size: 20px; --body-20-leading: 1.50; --body-20-tracking: -0.015em; --body-20-weight: 400;
  --body-18-size: 18px; --body-18-leading: 1.55; --body-18-tracking: -0.013em; --body-18-weight: 400;
  --body-16-size: 16px; --body-16-leading: 1.55; --body-16-tracking: -0.011em; --body-16-weight: 400;
  --body-14-size: 14px; --body-14-leading: 1.55; --body-14-tracking: -0.006em; --body-14-weight: 400;
  --body-13-size: 13px; --body-13-leading: 1.50; --body-13-tracking: -0.005em; --body-13-weight: 400;

  /* Caption family (Inter 400). Positive tracking on caption-11
     signals "taxonomy marker" without going uppercase. */
  --caption-12-size: 12px; --caption-12-leading: 1.40; --caption-12-tracking: 0;       --caption-12-weight: 400;
  --caption-11-size: 11px; --caption-11-leading: 1.35; --caption-11-tracking: 0.005em; --caption-11-weight: 400;

  /* Button family (Inter 500). Tight leading for label-in-control fit. */
  --button-16-size: 16px; --button-16-leading: 1.20; --button-16-tracking: -0.011em; --button-16-weight: 500;
  --button-14-size: 14px; --button-14-leading: 1.20; --button-14-tracking: -0.006em; --button-14-weight: 500;
  --button-12-size: 12px; --button-12-leading: 1.20; --button-12-tracking: 0;        --button-12-weight: 500;

  /* Eyebrow (Inter 500 + positive tracking). Section taxonomy marker. */
  --eyebrow-size: 13px; --eyebrow-leading: 1.30; --eyebrow-tracking: 0.04em; --eyebrow-weight: 500;

  /* Mono family (JetBrains Mono 400). Code contexts only. */
  --mono-14-size: 14px; --mono-14-leading: 1.55; --mono-14-tracking: 0; --mono-14-weight: 400;
  --mono-13-size: 13px; --mono-13-leading: 1.50; --mono-13-tracking: 0; --mono-13-weight: 400;
  --mono-12-size: 12px; --mono-12-leading: 1.45; --mono-12-tracking: 0; --mono-12-weight: 400;

  /* Spacing scale. Base unit 4px, every step a multiple. */
  --space-4:  4px;
  --space-8:  8px;
  --space-12: 12px;
  --space-16: 16px;
  --space-24: 24px;
  --space-32: 32px;
  --space-40: 40px;
  --space-64: 64px;
  --space-96: 96px;
}

/* ---------------------------------------------------------------
 * Dark-mode override. Same intent contract, inverted values.
 *
 * Neutral grays -- no blue/cool tint. Canvas is deliberately not pure
 * #000000: #0F0F10 keeps a warm-neutral read on OLED and prevents the
 * surface ladder from banding on cheap panels. surface-1 sits at the
 * "lifted popup" rung; surface-2 is the active-row highlight.
 *
 * Status roles are theme-invariant (no override); the -fg pair still
 * carries the same label color because meaning doesn't flip with theme.
 * --------------------------------------------------------------- */
.dark {
  --canvas:    #0F0F10;
  --surface-1: #1B1B1C;
  --surface-2: #222224;
  --surface-3: #2A2A2C;
  --surface-4: #313134;

  /* Elevated surface for popups. Dark mode sits one rung above canvas;
     the -hover step lifts one nudge toward surface-2. */
  --surface-elevated:       #1B1B1C;
  --surface-elevated-hover: #232324;

  --hairline:           rgba(255, 255, 255, 0.06);
  --hairline-strong:    rgba(255, 255, 255, 0.11);
  --hairline-tertiary:  rgba(255, 255, 255, 0.18);

  --ink:           #F5F5F5;
  --ink-muted:     #9D9DA0;
  --ink-subtle:    #7C7C80;
  --ink-tertiary:  #6E6E71;

  /* Primary reinherits the inverted ink/canvas automatically through
     the var chain; the entries above already updated. Consumers that
     override --primary in light also override in dark. */

  /* --focus-ring-color inherits var(--primary), which now resolves to
     the dark-mode ink (#EDEDED) automatically -- no explicit dark-mode
     override needed. */

  /* Shadows deepen to compensate for reduced contrast on the near-black
     canvas. */
  --shadow-card:
    0 2px 2px rgba(0, 0, 0, 0.4);
  --shadow-menu:
    0 1px 1px rgba(0, 0, 0, 0.3),
    0 4px 8px -4px rgba(0, 0, 0, 0.4),
    0 16px 24px -8px rgba(0, 0, 0, 0.5);
  --shadow-modal:
    0 1px 1px rgba(0, 0, 0, 0.3),
    0 8px 16px -4px rgba(0, 0, 0, 0.4),
    0 24px 32px -8px rgba(0, 0, 0, 0.5);
}

/* Loading dots: 3 dots pulse in staggered sequence. */
@keyframes patch-dots-pulse {
  0%, 80%, 100% { opacity: 0.25; transform: scale(0.6); }
  40% { opacity: 1; transform: scale(1); }
}

/* Progress bar: indeterminate sweep from left to right. */
@keyframes patch-progress-indeterminate {
  0% { transform: translateX(-100%); }
  100% { transform: translateX(400%); }
}

/* Skeleton placeholder: gentle opacity pulse. Range kept narrow so the
   block stays legibly present through the whole cycle. */
@keyframes patch-skeleton-pulse {
  0%, 100% { opacity: 1; }
  50%      { opacity: 0.65; }
}

/* Reduced motion overrides both durations to 0ms; animations still
   fire but resolve instantly. */
@media (prefers-reduced-motion: reduce) {
  :root {
    --duration-state:   0ms;
    --duration-overlay: 0ms;
    --ease-standard:    ease;
  }
}

/* ---------------------------------------------------------------
 * Layer 2: Tailwind bridge (@theme inline).
 *
 * Exposes runtime tokens as Tailwind utility slots:
 *   - Every color as --color-* (bg-canvas, text-ink, border-hairline)
 *   - Every radius as --radius-*
 *   - Every shadow as --shadow-*
 *   - Motion easing as --ease-*
 *
 * Spacing lives at :root as --space-* only. Exposing --spacing-N here
 * would collide with Tailwind's h-N/p-N/gap-N default multiplier and
 * break sizing utilities.
 *
 * Type sizes are NOT exposed as --text-*; the compound utility classes
 * in Layer 3 already declare size + leading + tracking + weight +
 * font-family in one shot.
 * --------------------------------------------------------------- */
@theme inline {
  --color-canvas:    var(--canvas);
  --color-surface-1: var(--surface-1);
  --color-surface-2: var(--surface-2);
  --color-surface-3: var(--surface-3);
  --color-surface-4: var(--surface-4);
  --color-surface-elevated:       var(--surface-elevated);
  --color-surface-elevated-hover: var(--surface-elevated-hover);

  --color-hairline:           var(--hairline);
  --color-hairline-strong:    var(--hairline-strong);
  --color-hairline-tertiary:  var(--hairline-tertiary);

  --color-ink:           var(--ink);
  --color-ink-muted:     var(--ink-muted);
  --color-ink-subtle:    var(--ink-subtle);
  --color-ink-tertiary:  var(--ink-tertiary);

  --color-primary:        var(--primary);
  --color-primary-hover:  var(--primary-hover);
  --color-primary-active: var(--primary-active);
  --color-on-primary:     var(--on-primary);

  --color-error:         var(--error);
  --color-error-hover:   var(--error-hover);
  --color-error-active:  var(--error-active);
  --color-error-fg:      var(--error-fg);
  --color-warning:        var(--warning);
  --color-warning-hover:  var(--warning-hover);
  --color-warning-active: var(--warning-active);
  --color-warning-fg:     var(--warning-fg);
  --color-success:        var(--success);
  --color-success-hover:  var(--success-hover);
  --color-success-active: var(--success-active);
  --color-success-fg:     var(--success-fg);

  --color-scrim: var(--scrim);

  --radius-4:    var(--radius-4);
  --radius-6:    var(--radius-6);
  --radius-12:   var(--radius-12);
  --radius-16:   var(--radius-16);
  --radius-full: var(--radius-full);

  --shadow-card:    var(--shadow-card);
  --shadow-menu:    var(--shadow-menu);
  --shadow-modal:   var(--shadow-modal);
  --shadow-tooltip: var(--shadow-tooltip);

  --ease-standard: var(--ease-standard);

  --font-display: var(--font-display);
  --font-body:    var(--font-body);
  --font-mono:    var(--font-mono);
}

/* ---------------------------------------------------------------
 * Layer 3: Compound text utility classes.
 *
 * Each .text-<family>-<size> applies size + line-height + tracking +
 * weight + font-family in one recipe. Components use these alone;
 * stacking a font-* weight utility on top is a lint-level error.
 * If a design needs a different weight at a given size, switch
 * families: display for 600, button/eyebrow for 500, body/caption/mono
 * for 400.
 * --------------------------------------------------------------- */
@layer utilities {
  .text-display-72 { font-family: var(--font-display); font-size: var(--display-72-size); line-height: var(--display-72-leading); letter-spacing: var(--display-72-tracking); font-weight: var(--display-72-weight); }
  .text-display-64 { font-family: var(--font-display); font-size: var(--display-64-size); line-height: var(--display-64-leading); letter-spacing: var(--display-64-tracking); font-weight: var(--display-64-weight); }
  .text-display-56 { font-family: var(--font-display); font-size: var(--display-56-size); line-height: var(--display-56-leading); letter-spacing: var(--display-56-tracking); font-weight: var(--display-56-weight); }
  .text-display-48 { font-family: var(--font-display); font-size: var(--display-48-size); line-height: var(--display-48-leading); letter-spacing: var(--display-48-tracking); font-weight: var(--display-48-weight); }
  .text-display-40 { font-family: var(--font-display); font-size: var(--display-40-size); line-height: var(--display-40-leading); letter-spacing: var(--display-40-tracking); font-weight: var(--display-40-weight); }
  .text-display-32 { font-family: var(--font-display); font-size: var(--display-32-size); line-height: var(--display-32-leading); letter-spacing: var(--display-32-tracking); font-weight: var(--display-32-weight); }
  .text-display-24 { font-family: var(--font-display); font-size: var(--display-24-size); line-height: var(--display-24-leading); letter-spacing: var(--display-24-tracking); font-weight: var(--display-24-weight); }
  .text-display-20 { font-family: var(--font-display); font-size: var(--display-20-size); line-height: var(--display-20-leading); letter-spacing: var(--display-20-tracking); font-weight: var(--display-20-weight); }

  .text-body-20 { font-family: var(--font-body); font-size: var(--body-20-size); line-height: var(--body-20-leading); letter-spacing: var(--body-20-tracking); font-weight: var(--body-20-weight); }
  .text-body-18 { font-family: var(--font-body); font-size: var(--body-18-size); line-height: var(--body-18-leading); letter-spacing: var(--body-18-tracking); font-weight: var(--body-18-weight); }
  .text-body-16 { font-family: var(--font-body); font-size: var(--body-16-size); line-height: var(--body-16-leading); letter-spacing: var(--body-16-tracking); font-weight: var(--body-16-weight); }
  .text-body-14 { font-family: var(--font-body); font-size: var(--body-14-size); line-height: var(--body-14-leading); letter-spacing: var(--body-14-tracking); font-weight: var(--body-14-weight); }
  .text-body-13 { font-family: var(--font-body); font-size: var(--body-13-size); line-height: var(--body-13-leading); letter-spacing: var(--body-13-tracking); font-weight: var(--body-13-weight); }

  .text-caption-12 { font-family: var(--font-body); font-size: var(--caption-12-size); line-height: var(--caption-12-leading); letter-spacing: var(--caption-12-tracking); font-weight: var(--caption-12-weight); }
  .text-caption-11 { font-family: var(--font-body); font-size: var(--caption-11-size); line-height: var(--caption-11-leading); letter-spacing: var(--caption-11-tracking); font-weight: var(--caption-11-weight); }

  .text-button-16 { font-family: var(--font-body); font-size: var(--button-16-size); line-height: var(--button-16-leading); letter-spacing: var(--button-16-tracking); font-weight: var(--button-16-weight); }
  .text-button-14 { font-family: var(--font-body); font-size: var(--button-14-size); line-height: var(--button-14-leading); letter-spacing: var(--button-14-tracking); font-weight: var(--button-14-weight); }
  .text-button-12 { font-family: var(--font-body); font-size: var(--button-12-size); line-height: var(--button-12-leading); letter-spacing: var(--button-12-tracking); font-weight: var(--button-12-weight); }

  .text-eyebrow { font-family: var(--font-body); font-size: var(--eyebrow-size); line-height: var(--eyebrow-leading); letter-spacing: var(--eyebrow-tracking); font-weight: var(--eyebrow-weight); }

  .text-mono-14 { font-family: var(--font-mono); font-size: var(--mono-14-size); line-height: var(--mono-14-leading); letter-spacing: var(--mono-14-tracking); font-weight: var(--mono-14-weight); }
  .text-mono-13 { font-family: var(--font-mono); font-size: var(--mono-13-size); line-height: var(--mono-13-leading); letter-spacing: var(--mono-13-tracking); font-weight: var(--mono-13-weight); }
  .text-mono-12 { font-family: var(--font-mono); font-size: var(--mono-12-size); line-height: var(--mono-12-leading); letter-spacing: var(--mono-12-tracking); font-weight: var(--mono-12-weight); }
}

/* Opt an individual scrollable surface out of any scrollbar. Companion
 * to the global thin-scrollbar defaults below. Declared with @utility
 * so it participates in Tailwind variants (md:scrollbar-hide,
 * hover:scrollbar-hide, etc.). */
@utility scrollbar-hide {
  -ms-overflow-style: none;
  scrollbar-width: none;
  &::-webkit-scrollbar {
    display: none;
  }
}

/* ---------------------------------------------------------------
 * Layer 4: base element styles.
 *
 * Thin, unobtrusive scrollbars applied globally. Thumb picks up
 * hairline-strong (0.13 alpha) and lifts to hairline-tertiary
 * (0.20 alpha) on hover, so it inverts naturally with the theme
 * without a per-mode override.
 *
 * Wrapped in @layer base so per-element consumer utilities (e.g.
 * [&::-webkit-scrollbar]:w-1) and unlayered overrides win the cascade
 * without needing !important. scrollbar-width and scrollbar-color are
 * inherited from :root; the ::-webkit-* pseudo-elements need the
 * wildcard since pseudo-elements don't inherit.
 * --------------------------------------------------------------- */
@layer base {
  :root {
    scrollbar-width: thin;
    scrollbar-color: var(--hairline-strong) transparent;
  }
  *::-webkit-scrollbar {
    width: 8px;
    height: 8px;
  }
  *::-webkit-scrollbar-track {
    background: transparent;
  }
  *::-webkit-scrollbar-thumb {
    background: var(--hairline-strong);
    border-radius: 999px;
  }
  *::-webkit-scrollbar-thumb:hover {
    background: var(--hairline-tertiary);
  }

  /* Icon default. Phosphor icons render with width="1em" / height="1em"
     attributes so they'd inherit the parent's font-size. Set a 1rem
     default here so an icon in a text-body-14 (14px) label still reads
     at 16px. Any Tailwind size-* class on the svg wins via selector
     specificity. */
  svg {
    width: 1rem;
    height: 1rem;
  }
}
